const knowledgeResponse = $('Fetch KNOWLEDGE.md').first().json;
const currentContentBase64 = knowledgeResponse.content || '';
const sha = knowledgeResponse.sha;

const currentContent = Buffer.from(currentContentBase64, 'base64').toString('utf8');

const aiResponse = JSON.parse($('Format Decision').first().json.message.content);
const formattedEntry = aiResponse.formatted_entry;
const entryNumber = aiResponse.entry_number;
const title = aiResponse.title;

const updatedContent = currentContent.trimEnd() + '\n\n' + formattedEntry + '\n';
const updatedBase64 = Buffer.from(updatedContent, 'utf8').toString('base64');

return [{
  json: {
    content: updatedBase64,
    sha: sha,
    message: `docs: log ${entryNumber} — ${title}`,
    entry_number: entryNumber,
    title: title
  }
}];
